import { stripURL } from './stripUrl';

export default function () {

  function isCollapseElement(element) {
    return element.getAttribute('data-toggle');
  }

  function getCtaName(element) {
    const overriddenName = element.getAttribute('data-cta-tracker-name');
    const title = element.getAttribute('title');
    const ariaLabel = element.getAttribute('aria-label')
    const fallback = element.innerText;

    const ctaName = overriddenName || title || ariaLabel || fallback;
    return ctaName.trim()
  }


  function getHumanReadableName(element) {
    if (isCollapseElement(element)) {
      return 'accordion'
    }

    if (element.classList.contains('.btn')) {
      return 'button';
    }

    const nodeName = element.nodeName;

    return {
      'A': 'link',
      'BUTTON': 'button',
    }[nodeName] || '';
  }

  function trackCta(clickEvent) {
    const element = clickEvent.currentTarget;
    const ctaContent = getCtaName(element)

    const humanReadableNodeName = getHumanReadableName(element)
    const eventAction = `User clicked the "${ctaContent}" ${humanReadableNodeName}`;

    const gtag = window.gtag || function (...args) {
      console.log('CTA-tracker: %s, %o', args[1], args[2]);
    }

    gtag('event', 'button_click', {
      event_category: 'ctaTrack',
      event_label: stripURL(window.location.pathname),
      event_action: eventAction,
    });
  }

  function setupCTATracking() {
    const selectors = ['a', 'button', '.btn', '[data-toggle]', '[data-cta-tracker-name]']
      .map(elem => `${elem}:not([data-cta-tracker-configured])`);

    document.querySelectorAll(selectors.join(', ')).forEach(element => {
      element.setAttribute('data-cta-tracker-configured', '')
      element.addEventListener('click', trackCta);
    });
  }

  setupCTATracking();
  const intervalId = setInterval(setupCTATracking, 1000);
  setTimeout(() => clearInterval(intervalId), 10000);
}
